# Read all patents data
all_patents_path = locals()['var_functions.query_db:24']
with open(all_patents_path, 'r') as f:
    all_patents = json.load(f)

# Extract California patents and create mapping
publication_to_assignee = {}
california_publications = set()
assignee_citations_found = {}

# First pass: collect all California publications
for patent in all_patents:
    patents_info = patent.get('Patents_info', '')
    if 'UNIV CALIFORNIA' in patents_info:
        pub_match = re.search(r'(US|WO|EP|AU|JP|KR|CN|CA|TW|RO|PT|IL|FR|DE)-[A-Z0-9]+-[A-Z0-9]+', patents_info)
        if pub_match:
            california_publications.add(pub_match.group())

# Second pass: find assignees that cite California patents
citing_assignees = {}

for patent in all_patents:
    patents_info = patent.get('Patents_info', '')

    # Skip California patents themselves
    if 'UNIV CALIFORNIA' in patents_info:
        continue

    # Get assignee name from this patent
    assignee_match = re.search(r'(.*?) holds? the |(.*?) assigned to |(.*?) belonging to |(.*?) owned by ', patents_info)
    current_assignee = None
    if assignee_match:
        for group in assignee_match.groups():
            if group:
                current_assignee = group.strip()
                break

    # Parse citations
    citation_data = patent.get('citation', '[]')
    if citation_data and citation_data != '[]':
        try:
            if isinstance(citation_data, str):
                citations = json.loads(citation_data)
            else:
                citations = citation_data

            for citation in citations:
                cited_pub = citation.get('publication_number')
                if cited_pub and cited_pub in california_publications:
                    # Found a citation to a California patent
                    if current_assignee not in citing_assignees:
                        citing_assignees[current_assignee] = {
                            'count': 0,
                            'cited_california_patents': set()
                        }
                    citing_assignees[current_assignee]['count'] += 1
                    citing_assignees[current_assignee]['cited_california_patents'].add(cited_pub)
        except:
            continue

# Prepare output
output = {
    'total_california_publications': len(california_publications),
    'citing_assignees_count': len(citing_assignees),
    'top_citing_assignees': []
}

# Sort by count and prepare top results
sorted_assignees = sorted(citing_assignees.items(), key=lambda x: x[1]['count'], reverse=True)
for assignee, info in sorted_assignees[:20]:
    output['top_citing_assignees'].append({
        'assignee': assignee,
        'citation_count': info['count'],
        'sample_cited_patents': list(info['cited_california_patents'])[:3]
    })

print('__RESULT__:')
print(json.dumps(output, indent=2))"}

{"code": "import json
import re

# Read all patents data
all_patents_path = locals()['var_functions.query_db:24']
with open(all_patents_path, 'r') as f:
    all_patents = json.load(f)

# Extract all UNIV CALIFORNIA publication numbers (from "pub. number" not "application number")
california_publications = set()

for patent in all_patents:
    patents_info = patent.get('Patents_info', '')

    if 'UNIV CALIFORNIA' in patents_info:
        # Find publication number (format: "pub. number US-2022074631-A1")
        pub_match = re.search(r'(?:has pub\. number |with publication no\. |with pub\. number |pub\. number )([A-Z]+-[A-Z0-9]+-[A-Z0-9]+)', patents_info)
        if pub_match:
            pub_num = pub_match.group(1)
            california_publications.add(pub_num)

# Now find patents that cite these California publications
citing_assignees = {}
california_patent_cpc_codes = {}  # Store CPC codes for each California patent

for patent in all_patents:
    patents_info = patent.get('Patents_info', '')

    # Skip if this is a California patent (we want citing patents, not cited ones)
    if 'UNIV CALIFORNIA' in patents_info:
        # Store CPC codes for this California patent
        pub_match = re.search(r'(?:has pub\. number |with publication no\. |with pub\. number |pub\. number )([A-Z]+-[A-Z0-9]+-[A-Z0-9]+)', patents_info)
        if pub_match:
            pub_num = pub_match.group(1)
            cpc_data = patent.get('cpc', '')
            if cpc_data:
                try:
                    if isinstance(cpc_data, str):
                        cpc_list = json.loads(cpc_data)
                    else:
                        cpc_list = cpc_data
                    # Extract CPC codes (primary and secondary)
                    cpc_codes = []
                    for cpc_item in cpc_list:
                        if isinstance(cpc_item, dict):
                            cpc_codes.append(cpc_item.get('code', ''))
                    california_patent_cpc_codes[pub_num] = cpc_codes
                except:
                    california_patent_cpc_codes[pub_num] = []
        continue

    # Get assignee of this patent (potential citing patent)
    current_assignee = None
    # Extract assignee name
    assignee_patterns = [
        r'^([^,]+?) holds the ',
        r'^([^,]+?) assigned to ',
        r'^([^,]+?) belonging to ',
        r'^([^,]+?) owned by ',
        r'^The ([^,]+?) (?:holds|assigned|belonging|owned)',
        r'^In [A-Z]{2}, the ([^,]+?) (?:holds|assigned|belonging|owned)',
        r'^Patent filing \([^\)]+?\) from [A-Z]{2}, (?:held|assigned|owned) by ([^,]+?)',
        r'^Application \([^\)]+?\) from [A-Z]{2}, (?:belonging|assigned|owned) to ([^,]+?)',
    ]

    for pattern in assignee_patterns:
        match = re.search(pattern, patents_info)
        if match and match.group(1):
            current_assignee = match.group(1).strip()
            # Remove trailing 'and' if present
            current_assignee = re.sub(r'\s+and$', '', current_assignee)
            break

    # Parse citations
    citation_data = patent.get('citation', '[]')
    if citation_data and citation_data != '[]':
        try:
            if isinstance(citation_data, str):
                citations = json.loads(citation_data)
            else:
                citations = citation_data

            for citation in citations:
                cited_pub = citation.get('publication_number')
                # Check if this patent cites a California publication
                if cited_pub and cited_pub in california_publications:
                    # Found a citation to a California patent
                    if current_assignee and 'UNIV CALIFORNIA' not in current_assignee:
                        if current_assignee not in citing_assignees:
                            citing_assignees[current_assignee] = {
                                'count': 0,
                                'cited_california_patents': set()
                            }
                        citing_assignees[current_assignee]['count'] += 1
                        citing_assignees[current_assignee]['cited_california_patents'].add(cited_pub)
        except:
            continue

# Prepare output
output = {
    'total_california_publications': len(california_publications),
    'citing_assignees_count': len(citing_assignees),
    'sample_california_cpc_codes': dict(list(california_patent_cpc_codes.items())[:3]),
    'top_citing_assignees': []
}

# Sort by count and prepare top results
sorted_assignees = sorted(citing_assignees.items(), key=lambda x: x[1]['count'], reverse=True)
for assignee, info in sorted_assignees[:20]:
    output['top_citing_assignees'].append({
        'assignee': assignee,
        'citation_count': info['count'],
        'sample_cited_patents': list(info['cited_california_patents'])[:3]
    })

print('__RESULT__:')
print(json.dumps(output, indent=2))"}

